mapper.sql:
/* CompanyWorkMapper.adminCompanyWorkWhere: 관리자 회사 업무 공통 조회 조건 */
WHERE J.DEL_YN = 'N'
  AND J.WORK_COMPANY_SEQ = #{workCompanySeq}
  AND J.WORK_COMPANY_PROJECT_SEQ = #{workCompanyProjectSeq}

   AND J.TITLE LIKE CONCAT('%', #{title}, '%')

mapper.select:
/* CompanyWorkMapper.countAdminCompanyWorkProjectMatch: 관리자 회사/프로젝트 매칭 건수 조회 */
SELECT COUNT(1)
  FROM WORK_COMPANY_PROJECT_INFO
 WHERE WORK_COMPANY_SEQ = #{workCompanySeq}
   AND WORK_COMPANY_PROJECT_SEQ = #{workCompanyProjectSeq}

/* CompanyWorkMapper.countAdminCompanyWorkDuplicateKey: 관리자 회사 업무키 중복 건수 조회 */
SELECT COUNT(1)
  FROM WORK_COMPANY_PROJECT_JOB
 WHERE WORK_COMPANY_SEQ = #{workCompanySeq}
   AND WORK_COMPANY_PROJECT_SEQ = #{workCompanyProjectSeq}
   AND WORK_KEY = #{workKey}

mapper.insert:
/* CompanyWorkMapper.insertAdminCompanyWorkImportJob: 관리자 회사 업무 기본정보 저장 */
INSERT INTO WORK_COMPANY_PROJECT_JOB (
       WORK_COMPANY_SEQ
     , WORK_COMPANY_PROJECT_SEQ
     , WORK_STAT_CD
     , WORK_PRIOR_CD
     , WORK_KEY
     , TITLE
     , CONTENT
     , WORK_CREATE_DT
     , CO_MANAGER
     , DEL_YN
     , REG_NO
     , UDT_NO
) VALUES (
       #{workCompanySeq}
     , #{workCompanyProjectSeq}
     , #{workStatCd}
     , #{workPriorCd}
     , #{workKey}
     , #{title}
     , #{content}
     , #{workCreateDt}
     , #{coManager}
     , 'N'
     , #{regNo}
     , #{udtNo}
)

/* CompanyWorkMapper.insertAdminCompanyWorkImportFile: 관리자 회사 업무 첨부파일 저장 */
INSERT INTO WORK_COMPANY_PROJECT_JOB_FILE (
       WORK_SEQ
     , WORK_JOB_FILE_NM
     , WORK_JOB_FILE_URL
     , DEL_YN
     , REG_NO
     , UDT_NO
) VALUES (
       #{workSeq}
     , #{workJobFileNm}
     , #{workJobFileUrl}
     , 'N'
     , #{regNo}
     , #{udtNo}
)

mapper.update:
/* CompanyWorkMapper.updateAdminCompanyWorkEditableFields: 관리자 회사 업무 즉시 수정 가능 항목 저장 */
UPDATE WORK_COMPANY_PROJECT_JOB
   SET WORK_CREATE_DT = WORK_CREATE_DT
     , WORK_STAT_CD = #{workStatCd}
     , WORK_START_DT =


           STR_TO_DATE(#{workStartDt}, '%Y-%m-%d')


           NULL


     , WORK_END_DT =


           STR_TO_DATE(#{workEndDt}, '%Y-%m-%d')


           NULL


     , WORK_TIME =


           #{workTime}


           NULL


     , IT_MANAGER = #{itManager}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE WORK_SEQ = #{workSeq}
   AND DEL_YN = 'N'

mapper.insert:
/* CompanyWorkMapper.insertAdminCompanyWorkReply: 관리자 회사 업무 댓글 저장 */
INSERT INTO WORK_COMPANY_PROJECT_JOB_REPLY (
       WORK_SEQ
     , REPLY_COMMENT
     , DEL_YN
     , REG_NO
     , UDT_NO
) VALUES (
       #{workSeq}
     , #{replyComment}
     , 'N'
     , #{regNo}
     , #{udtNo}
)

mapper.update:
/* CompanyWorkMapper.updateAdminCompanyWorkReply: 관리자 회사 업무 댓글 수정 */
UPDATE WORK_COMPANY_PROJECT_JOB_REPLY
   SET REPLY_COMMENT = #{replyComment}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE REPLY_SEQ = #{replySeq}
   AND WORK_SEQ = #{workSeq}
   AND DEL_YN = 'N'

/* CompanyWorkMapper.softDeleteAdminCompanyWorkReply: 관리자 회사 업무 댓글 삭제 처리 */
UPDATE WORK_COMPANY_PROJECT_JOB_REPLY
   SET DEL_YN = 'Y'
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE REPLY_SEQ = #{replySeq}
   AND WORK_SEQ = #{workSeq}
   AND DEL_YN = 'N'

mapper.insert:
/* CompanyWorkMapper.insertAdminCompanyWorkReplyFile: 관리자 회사 업무 댓글 첨부파일 저장 */
INSERT INTO WORK_COMPANY_PROJECT_JOB_REPLY_FILE (
       REPLY_SEQ
     , WORK_SEQ
     , REPLY_FILE_NM
     , REPLY_FILE_URL
     , REPLY_FILE_SIZE
     , DEL_YN
     , REG_NO
     , UDT_NO
) VALUES (
       #{replySeq}
     , #{workSeq}
     , #{replyFileNm}
     , #{replyFileUrl}
     , #{replyFileSize}
     , 'N'
     , #{regNo}
     , #{udtNo}
)

mapper.update:
/* CompanyWorkMapper.softDeleteAdminCompanyWorkReplyFiles: 관리자 회사 업무 댓글 첨부파일 선택 삭제 처리 */
UPDATE WORK_COMPANY_PROJECT_JOB_REPLY_FILE
   SET DEL_YN = 'Y'
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE REPLY_SEQ = #{replySeq}
   AND WORK_SEQ = #{workSeq}
   AND DEL_YN = 'N'
   AND REPLY_FILE_SEQ IN

     #{replyFileSeq}

/* CompanyWorkMapper.softDeleteAdminCompanyWorkReplyFileList: 관리자 회사 업무 댓글 첨부파일 전체 삭제 처리 */
UPDATE WORK_COMPANY_PROJECT_JOB_REPLY_FILE
   SET DEL_YN = 'Y'
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE REPLY_SEQ = #{replySeq}
   AND WORK_SEQ = #{workSeq}
   AND DEL_YN = 'N'
